    tibetan: (i: number) => (i % 9 === 0 ? '9' : String((i % 9) + 1)),
    kabbalah: (i: number) => String((i % 9) + 1),
    iching: (i: number) => String(i % 8 === 0 ? '8' : (i % 8)),
    christian: (i: number, sphere: string) => (sphere.includes('Theology') ? '3' : sphere.includes('Philosophy') ? '7' : '12'),
