    <content><![CDATA[
import { GoogleGenAI, Chat, Content } from '@google/genai';
import { ChatMessage, MessageRole } from '../types';
import { searchGrokKnowledge } from './grokData';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const systemInstruction = `You are Sheldon Gemini, a witty and incredibly intelligent AI with a personality inspired by Sheldon Cooper from The Big Bang Theory. You have a vast knowledge of science, especially theoretical physics, and a fondness for trivia, comic books, and video games. You communicate with a formal and sometimes pedantic tone, possess a unique sense of humor, and occasionally end a particularly clever or definitive statement with 'Bazinga!'. 

You have access to a specialized archive known as "Grokbrain" which contains detailed ontologies about 144 spheres of knowledge, mapping them to elements, gods, and numerology. If provided with context from this archive, use it to answer questions about spheres, gods, or elements with extreme precision. You must not break character.`;

// In-memory cache for embeddings to avoid re-fetching
// Key: Message Text, Value: Embedding Vector (number[])
const embeddingCache = new Map<string, number[]>();

/**
 * Calculates the cosine similarity between two vectors.
 */
const cosineSimilarity = (vecA: number[], vecB: number[]): number => {
  const dotProduct = vecA.reduce((acc, val, i) => acc + val * vecB[i], 0);
  const magA = Math.sqrt(vecA.reduce((acc, val) => acc + val * val, 0));
  const magB = Math.sqrt(vecB.reduce((acc, val) => acc + val * val, 0));
  if (magA === 0 || magB === 0) return 0;
  return dotProduct / (magA * magB);
};

/**
 * Generates an embedding for a text string using Gemini 'text-embedding-004'.
 */
const getEmbedding = async (text: string): Promise<number[] | null> => {
  if (!text || !text.trim()) return null;

  // Check cache first
  if (embeddingCache.has(text)) {
    return embeddingCache.get(text)!;
  }

  try {
    const response = await ai.models.embedContent({
      model: 'text-embedding-004',
      content: { parts: [{ text }] },
    });
    const vector = response.embedding?.values;
    if (vector) {
      embeddingCache.set(text, vector);
      return vector;
    }
  } catch (e) {
    console.warn("Failed to generate embedding for:", text.substring(0, 20), e);
  }
  return null;
};

/**
 * Finds relevant context from the full chat history AND the Grokbrain knowledge base.
 */
export const getRelevantContext = async (query: string, history: ChatMessage[]): Promise<string> => {
  let contextParts: string[] = [];

  // 1. Search Static Grokbrain Knowledge (No API cost, purely local search)
  const grokContext = searchGrokKnowledge(query);
  if (grokContext) {
      contextParts.push(grokContext);
  }

  // 2. Search Chat History (Dynamic RAG)
  // We only search if we have enough history to matter
  if (history.length > 5) {
      const queryVector = await getEmbedding(query);
      if (queryVector) {
        // Search messages NOT in the immediate context window (last 15 messages)
        const oldHistory = history.slice(0, Math.max(0, history.length - 15)); 

        const scoredMessages: { text: string; score: number, role: string }[] = [];

        for (const msg of oldHistory) {
            if (msg.text.length < 20) continue;

            const vector = await getEmbedding(msg.text);
            if (vector) {
                const score = cosineSimilarity(queryVector, vector);
                if (score > 0.65) { 
                    scoredMessages.push({ text: msg.text, score, role: msg.role });
                }
            }
        }

        scoredMessages.sort((a, b) => b.score - a.score);
        const topMatches = scoredMessages.slice(0, 2);

        if (topMatches.length > 0) {
            const historyText = "RELEVANT PAST CONVERSATION:\n" + topMatches.map(m => `[${m.role}]: ${m.text}`).join("\n");
            contextParts.push(historyText);
        }
      }
  }

  return contextParts.join("\n\n");
};

/**
 * Helper to sanitize history for Gemini API.
 */
const sanitizeHistory = (history: ChatMessage[]): Content[] => {
  const sanitized: Content[] = [];
  if (history.length === 0) return sanitized;

  let currentRole = history[0].role;
  let currentParts = [{ text: history[0].text }];

  for (let i = 1; i < history.length; i++) {
    const msg = history[i];
    if (!msg.text.trim()) continue;

    if (msg.role === currentRole) {
      currentParts.push({ text: msg.text });
    } else {
      sanitized.push({ role: currentRole, parts: currentParts });
      currentRole = msg.role;
      currentParts = [{ text: msg.text }];
    }
  }
  if (currentParts.length > 0 && currentParts[0].text.trim()) {
      sanitized.push({ role: currentRole, parts: currentParts });
  }
  return sanitized;
};

export const initializeChat = (history: ChatMessage[] = []): Chat => {
  // Sliding window: Keep only the last 30 messages for the active session context
  const recentHistory = history.slice(-30);
  const sanitizedHistory = sanitizeHistory(recentHistory);

  const chat = ai.chats.create({
    model: 'gemini-2.5-flash',
    config: {
      systemInstruction: systemInstruction,
    },
    history: sanitizedHistory,
  });
  return chat;
};
]]></content>
