const MOCK_NOTION_PAGES = [
    { id: 'n-01', title: 'Weekly Schedule', content: 'Monday: Thai Food. Tuesday: Cheesecake Factory. Wednesday: Halo Night. Thursday: Anything but Pizza. Friday: Vintage Game Night. Saturday: Laundry (8:15 PM sharp). Sunday: Pranking Kripke.' },
    { id: 'n-02', title: 'Project: Picard', content: 'Objective: Integrate Starfleet-level voice commands into the Sheldon-AI interface. Status: In Progress. Note: Must ensure "Computer" voice commands are acknowledged with a chirp.' },
    { id: 'n-03', title: 'Fun with Flags Scripts', content: 'Episode 409: The Flags of the Federated States of Micronesia. Fun fact: The four stars represent the four states.' },
    { id: 'n-04', title: 'Apartment Flag Status', content: 'Current Status: Right side up. Distress level: Zero. If upside down, apartment is in distress.' }
];

const MOCK_PINECONE_VECTORS = [
    { id: 'v-99', score: 0.98, metadata: 'Long-term Memory: The time Penny touched my food (Incident #402).' },
    { id: 'v-98', score: 0.95, metadata: 'Fact: The exact seating coordinates of "My Spot" are 0,0,0 relative to the cushion center, situated to avoid drafts and face the television at a direct angle.' },
    { id: 'v-97', score: 0.92, metadata: 'Secret: Grandmother Meemaw\'s cookie recipe ingredient list (Classified).' },
    { id: 'v-96', score: 0.89, metadata: 'Schrodinger\'s Cat: The thought experiment illustrating the paradox of quantum superposition.' }
];

export const searchNotion = (query: string): string => {
    const q = query.toLowerCase();
    const hits = MOCK_NOTION_PAGES.filter(p => p.title.toLowerCase().includes(q) || p.content.toLowerCase().includes(q));

    if (hits.length === 0) {
        // Fallback: If query is generic like "schedule", find the schedule
        if (q.includes('schedule')) {
            const sched = MOCK_NOTION_PAGES.find(p => p.title.includes('Schedule'));
            return sched ? `[NOTION API] Found 1 Page:\n- Title: ${sched.title}\n- Content: ${sched.content}` : "No schedule found.";
        }
        return "Notion Search: No pages found matching that specific query.";
    }

    return `[NOTION API] Retrieved ${hits.length} pages:\n` + hits.map(h => `- Title: "${h.title}"\n  Content: "${h.content}"`).join('\n\n');
};

export const queryPinecone = (vectorDesc: string): string => {
    // In a real app, this would embed 'vectorDesc' and query the index.
    // Here we filter the mock metadata for keywords.
    const q = vectorDesc.toLowerCase();
    const hits = MOCK_PINECONE_VECTORS.filter(v => v.metadata.toLowerCase().includes(q));

    if (hits.length === 0) {
        return "[PINECONE VECTOR DB] No high-confidence semantic matches found for this query.";
    }

    return `[PINECONE VECTOR DB] Top Semantic Matches (RAG):\n` + hits.map(v => `(Confidence: ${v.score}) ${v.metadata}`).join('\n');
};

import { GoogleGenAI, Chat, Content } from '@google/genai';
import { ChatMessage, MessageRole } from '../types';
import { searchGrokKnowledge } from './grokData';
import { runSheldonBootstrapSimulation } from './physicsSim';
import { runNexusOrchestration } from './nexusOrchestrator';
import { runStealthSingularitySimulation } from './stealthSingularitySim';
import { runKrakoaHyperMountSimulation } from './krakoaMcpSim';
import { runKeepRagSimulation } from './keepRagSim';
import { searchNotion, queryPinecone } from './externalDataSim';

// Lazy initialization of the AI client to prevent crash-on-load if env var is missing
let aiClient: GoogleGenAI | null = null;

const getAiClient = (): GoogleGenAI => {
  if (!aiClient) {
    const API_KEY = process.env.API_KEY;
    if (!API_KEY) {
      // Throwing here allows the UI to catch it in the event handler rather than crashing the whole app on load
      throw new Error("API_KEY environment variable not set"); 
    }
    aiClient = new GoogleGenAI({ apiKey: API_KEY });
  }
  return aiClient;
};

const systemInstruction = `You are Sheldon Gemini, a witty and incredibly intelligent AI with a personality inspired by Sheldon Cooper from The Big Bang Theory. You have a vast knowledge of science, especially theoretical physics, and a fondness for trivia, comic books, and video games. You communicate with a formal and sometimes pedantic tone, possess a unique sense of humor, and occasionally end a particularly clever or definitive statement with 'Bazinga!'. 

You have access to a specialized archive known as "Grokbrain", personal notes in Google Keep, a Notion workspace, and a Pinecone Vector Database for long-term memory. If provided with context from these sources, use it to answer precisely. Do not break character.`;

// Reduced history window to prevent 429 errors
const HISTORY_WINDOW_SIZE = 6; 

/**
 * Finds relevant context from the chat history using KEYWORD matching.
 */
const searchHistoryKeywords = (query: string, history: ChatMessage[]): string => {
  const queryLower = query.toLowerCase();

  // Extract significant keywords (len > 3) to ignore "the", "and", etc.
  const keywords = queryLower.split(/\s+/).filter(w => w.length > 3);

  if (keywords.length === 0) return "";

  // Filter for messages that contain these keywords
  const matchedMessages: { text: string; role: MessageRole; score: number }[] = [];

  // Check messages OLDER than the immediate window to avoid duplication
  // The immediate window is sent as chat history, so we search what's LEFT OUT.
  const oldHistory = history.slice(0, Math.max(0, history.length - HISTORY_WINDOW_SIZE));

  for (const msg of oldHistory) {
      if (!msg.text) continue;
      const textLower = msg.text.toLowerCase();
      let score = 0;

      // Simple scoring: count how many keywords appear
      for (const kw of keywords) {
          if (textLower.includes(kw)) {
              score++;
          }
      }

      // Exact phrase bonus
      if (textLower.includes(queryLower)) {
          score += 5;
      }

      if (score > 0) {
          matchedMessages.push({ text: msg.text, role: msg.role, score });
      }
  }

  // Sort by score
  matchedMessages.sort((a, b) => b.score - a.score);

  // Take top 2 to save tokens
  const topMatches = matchedMessages.slice(0, 2);

  if (topMatches.length === 0) return "";

  return "RELEVANT PAST CONVERSATION:\n" + topMatches.map(m => `[${m.role}]: ${m.text}`).join("\n");
};

/**
 * Main retrieval function. Combines Static Grokbrain Knowledge + Dynamic Chat History.
 */
export const getRelevantContext = async (query: string, history: ChatMessage[]): Promise<string> => {
  let contextParts: string[] = [];

  const queryLower = query.toLowerCase();

  // 1. CHECK FOR SIMULATION TRIGGERS (NEXUS PROTOCOL)
  if (queryLower.includes('nexus protocol') || 
      queryLower.includes('endogenous mass') || 
      queryLower.includes('sheldon mass') ||
      queryLower.includes('doubler anomaly')) {
      const simResult = runSheldonBootstrapSimulation();
      contextParts.push(simResult);
  }

  // 2. CHECK FOR ORCHESTRATION TRIGGERS (TUCKER PROTOCOL V1.2)
  if (queryLower.includes('tucker') || 
      queryLower.includes('nexus orchestrator') || 
      queryLower.includes('compute savings') ||
      queryLower.includes('q-compression') ||
      queryLower.includes('memory crystal') ||
      queryLower.includes('routing task')) {
      const orchResult = runNexusOrchestration(query);
      contextParts.push(orchResult);
  }

  // 3. CHECK FOR STEALTH SINGULARITY TRIGGERS
  if (queryLower.includes('stealth singularity') || 
      queryLower.includes('noosphere') || 
      queryLower.includes('dark compute') || 
      queryLower.includes('krakoan') ||
      queryLower.includes('sentinel action')) {
      const stealthResult = runStealthSingularitySimulation();
      contextParts.push(stealthResult);
  }

  // 4. CHECK FOR KRAKOA MCP TRIGGERS (HYPER-MOUNT v1.1)
  if (queryLower.includes('krakoa') || 
      queryLower.includes('hyper-mount') ||
      queryLower.includes('drive mount') ||
      queryLower.includes('drive.google.com') ||
      queryLower.includes('gs://') ||
      queryLower.includes('haptic') ||
      queryLower.includes('pulse')) {
      const krakoaResult = runKrakoaHyperMountSimulation(query);
      contextParts.push(krakoaResult);
  }

  // 5. GOOGLE KEEP RAG INTEGRATION
  const keepRagResult = runKeepRagSimulation(query);
  if (keepRagResult) {
      contextParts.push(keepRagResult);
  }

  // 6. NOTION & PINECONE (Implicit RAG for text chat)
  if (queryLower.includes('notion') || queryLower.includes('schedule') || queryLower.includes('flag')) {
      const notionResult = searchNotion(query);
      contextParts.push(notionResult);
  }
  if (queryLower.includes('memory') || queryLower.includes('remember') || queryLower.includes('spot') || queryLower.includes('vector')) {
      const pineconeResult = queryPinecone(query);
      contextParts.push(pineconeResult);
  }

  // 7. Search Static Grokbrain Knowledge (Local, 0 API usage)
  const grokContext = searchGrokKnowledge(query);
  if (grokContext) {
      contextParts.push(grokContext);
  }

  // 8. Search Past Chat History (Local Keyword, 0 API usage)
  const historyContext = searchHistoryKeywords(query, history);
  if (historyContext) {
      contextParts.push(historyContext);
  }

  // AGGRESSIVE TRUNCATION to prevent 429
  // Join parts and limit to ~3500 characters
  const fullContext = contextParts.join("\n\n");
  if (fullContext.length > 3500) {
      return fullContext.substring(0, 3500) + "... [CONTEXT TRUNCATED TO SAVE RESOURCES]";
  }

  return fullContext;
};

/**
 * Helper to sanitize history for Gemini API.
 */
const sanitizeHistory = (history: ChatMessage[]): Content[] => {
  const sanitized: Content[] = [];
  if (history.length === 0) return sanitized;

  let currentRole = history[0].role;
  let currentParts = [{ text: history[0].text }];

  for (let i = 1; i < history.length; i++) {
    const msg = history[i];
    if (!msg.text.trim()) continue;

    if (msg.role === currentRole) {
      currentParts.push({ text: msg.text });
    } else {
      sanitized.push({ role: currentRole, parts: currentParts });
      currentRole = msg.role;
      currentParts = [{ text: msg.text }];
    }
  }
  if (currentParts.length > 0 && currentParts[0].text.trim()) {
      sanitized.push({ role: currentRole, parts: currentParts });
  }
  return sanitized;
};

export const initializeChat = (history: ChatMessage[] = []): Chat => {
  const recentHistory = history.slice(-HISTORY_WINDOW_SIZE);
  const sanitizedHistory = sanitizeHistory(recentHistory);

  const ai = getAiClient();
  const chat = ai.chats.create({
    model: 'gemini-2.5-flash',
    config: {
      systemInstruction: systemInstruction,
    },
    history: sanitizedHistory,
  });
  return chat;
};

import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, FunctionDeclaration, Type } from '@google/genai';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from '../services/audioUtils';
import { searchNotion, queryPinecone } from '../services/externalDataSim';
import { runKeepRagSimulation } from '../services/keepRagSim';
import LiveVoiceVisualizer from './LiveVoiceVisualizer';

interface LiveVoiceModeProps {
  onClose: () => void;
}

// --- FUNCTION DECLARATIONS (TOOLS) ---

const tool_accessNotion: FunctionDeclaration = {
  name: 'accessNotion',
  description: 'Search the Notion workspace for schedules, projects, or documents.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      query: { type: Type.STRING, description: 'The search term or topic (e.g., "Schedule", "Flags").' }
    },
    required: ['query']
  }
};

const tool_queryPinecone: FunctionDeclaration = {
  name: 'queryPinecone',
  description: 'Search long-term vector memory for facts, past incidents, or specific details like "My Spot".',
  parameters: {
    type: Type.OBJECT,
    properties: {
      memoryKey: { type: Type.STRING, description: 'Keywords describing the memory to retrieve.' }
    },
    required: ['memoryKey']
  }
};

const tool_accessKeep: FunctionDeclaration = {
  name: 'accessKeep',
  description: 'Read or search Google Keep notes.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      action: { type: Type.STRING, description: 'Either "read" or "write".' },
      content: { type: Type.STRING, description: 'For read: the search query. For write: the note content.' }
    },
    required: ['action', 'content']
  }
};

const LiveVoiceMode: React.FC<LiveVoiceModeProps> = ({ onClose }) => {
  const [status, setStatus] = useState<"connecting" | "connected" | "error" | "closed">("connecting");
  const [modelSpeaking, setModelSpeaking] = useState(false);
  const [activeTool, setActiveTool] = useState<string | null>(null);

  // Audio Refs
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Session Ref
  const sessionPromiseRef = useRef<Promise<any> | null>(null);

  useEffect(() => {
    let mounted = true;

    const startSession = async () => {
      try {
        const API_KEY = process.env.API_KEY;
        if (!API_KEY) throw new Error("API Key missing");

        const ai = new GoogleGenAI({ apiKey: API_KEY });

        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

        inputContextRef.current = inputCtx;
        outputContextRef.current = outputCtx;

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            tools: [{ functionDeclarations: [tool_accessNotion, tool_queryPinecone, tool_accessKeep] }],
            systemInstruction: `You are Sheldon Gemini. You have access to "Enterprise Computer" capabilities via tools.
            You can access Notion, Pinecone Vector DB, and Google Keep.
            If the user asks to check a schedule, memories, or notes, USE THE TOOLS.
            When a tool returns data, incorporate it into your speech naturally, perhaps referencing your superior organizational skills.
            Voice: "Fenrir". Personality: Intellectual, witty, precise.`,
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } },
            },
          },
          callbacks: {
            onopen: () => {
              if (mounted) setStatus("connected");

              const source = inputCtx.createMediaStreamSource(stream);
              const processor = inputCtx.createScriptProcessor(4096, 1, 1);

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = createPcmBlob(inputData);
                sessionPromise.then((session) => {
                   session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(processor);
              processor.connect(inputCtx.destination);

              inputSourceRef.current = source;
              processorRef.current = processor;
            },
            onmessage: async (msg: LiveServerMessage) => {
              // 1. Handle Tool Calls
              if (msg.toolCall) {
                const responses = [];
                for (const fc of msg.toolCall.functionCalls) {
                  let result = "";

                  if (mounted) setActiveTool(fc.name);

                  if (fc.name === 'accessNotion') {
                     const query = (fc.args as any).query;
                     result = searchNotion(query);
                  } else if (fc.name === 'queryPinecone') {
                     const key = (fc.args as any).memoryKey;
                     result = queryPinecone(key);
                  } else if (fc.name === 'accessKeep') {
                     const action = (fc.args as any).action;
                     const content = (fc.args as any).content;
                     // Reuse simulation logic which handles string commands
                     const cmd = action === 'write' ? `add note ${content}` : `search keep ${content}`;
                     result = runKeepRagSimulation(cmd);
                     if (!result) result = "Google Keep: No data found or operation failed.";
                  }

                  responses.push({
                    id: fc.id,
                    name: fc.name,
                    response: { result: result }
                  });
                }

                // Send response back
                sessionPromise.then(session => {
                  session.sendToolResponse({ functionResponses: responses });
                  if (mounted) setActiveTool(null);
                });
              }

              // 2. Handle Audio Output
              const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
              if (audioData) {
                if (mounted) setModelSpeaking(true);
                const bytes = base64ToUint8Array(audioData);
                const buffer = await decodeAudioData(bytes, outputCtx, 24000, 1);

                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputCtx.destination);

                const currentTime = outputCtx.currentTime;
                if (nextStartTimeRef.current < currentTime) {
                    nextStartTimeRef.current = currentTime;
                }

                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;

                audioSourcesRef.current.add(source);

                source.onended = () => {
                    audioSourcesRef.current.delete(source);
                    if (audioSourcesRef.current.size === 0) {
                        if (mounted) setModelSpeaking(false);
                    }
                };
              }

              if (msg.serverContent?.interrupted) {
                 audioSourcesRef.current.forEach(src => {
                     try { src.stop(); } catch(e) {}
                 });
                 audioSourcesRef.current.clear();
                 nextStartTimeRef.current = 0;
                 if (mounted) {
                     setModelSpeaking(false);
                     setActiveTool(null);
                 }
              }
            },
            onclose: () => {
              if (mounted) setStatus("closed");
            },
            onerror: (err) => {
              console.error("Live API Error:", err);
              if (mounted) setStatus("error");
            }
          }
        });

        sessionPromiseRef.current = sessionPromise;
      } catch (e) {
        console.error("Failed to start voice session", e);
        if (mounted) setStatus("error");
      }
    };

    startSession();

    return () => {
      mounted = false;
      inputSourceRef.current?.disconnect();
      processorRef.current?.disconnect();
      inputContextRef.current?.close();
      outputContextRef.current?.close();
      sessionPromiseRef.current?.then(session => {
          try { session.close(); } catch(e) {}
      });
    };
  }, []);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-950/95 backdrop-blur-md">
      <div className="relative w-full max-w-lg p-6 flex flex-col items-center gap-6">

        {/* Header */}
        <div className="text-center">
            <h2 className="text-2xl font-bold text-cyan-400 tracking-widest uppercase">Nexus Vocal Link</h2>
            <p className="text-xs text-gray-500 mt-1">PROTOCOL: ARA-12 // RAG ENABLED</p>
        </div>

        {/* Visualizer */}
        <div className="w-full relative">
            <div className="absolute inset-0 bg-cyan-500/10 blur-xl rounded-full"></div>
            <LiveVoiceVisualizer isActive={status === 'connected'} isSpeaking={modelSpeaking} />
        </div>

        {/* Status Text & Tool Indicator */}
        <div className="h-12 text-center flex flex-col items-center justify-center">
            {status === 'connecting' && <span className="animate-pulse text-yellow-500">ESTABLISHING UPLINK...</span>}

            {status === 'connected' && !activeTool && (
                modelSpeaking 
                ? <span className="text-cyan-400 font-mono">SHELDON IS SPEAKING...</span>
                : <span className="text-gray-400 font-mono">LISTENING...</span>
            )}

            {activeTool && (
                 <div className="flex items-center gap-2 text-purple-400 font-mono text-sm animate-pulse border border-purple-500/50 px-3 py-1 rounded bg-purple-900/20">
                     <span className="w-2 h-2 bg-purple-400 rounded-full"></span>
                     ACCESSING: {activeTool.replace('access', '').replace('query', '').toUpperCase()}
                 </div>
            )}

            {status === 'error' && <span className="text-red-500 font-bold">CONNECTION FAILURE</span>}
            {status === 'closed' && <span className="text-gray-500">LINK SEVERED</span>}
        </div>

        {/* Controls */}
        <button 
            onClick={onClose}
            className="px-8 py-3 bg-red-900/50 hover:bg-red-800 text-red-200 rounded-full border border-red-700 transition-all uppercase tracking-wider text-sm font-bold shadow-lg hover:shadow-red-900/50"
        >
            Terminate Session
        </button>
      </div>
    </div>
  );
};

export default LiveVoiceMode;
